VALUES (3688,394,1814,NULL,3,0,'Please describe each dataset and software your project will produce.','{"meta": {"title": "Research Output Table", "schemaVersion": "1.0", "usageDescription": "A table for collecting structured research output data"}, "type": "researchOutputTable", "columns": [{"help": "Enter the title of this research output", "content": {"meta": {"schemaVersion": "1.0"}, "type": "text", "attributes": {"maxLength": 120}}, "enabled": true, "heading": "Title", "required": true}, {"help": "Enter a brief description of this research output", "content": {"meta": {"schemaVersion": "1.0"}, "type": "textArea", "attributes": {"cols": 20, "help": "Tell us all about it!", "rows": 2, "label": "Description", "maxLength": 10000, "asRichText": true, "labelTranslationKey": "labels.description"}}, "enabled": true, "heading": "Description", "required": false}, {"help": "Select the type of this research output", "content": {"meta": {"schemaVersion": "1.0"}, "type": "selectBox", "options": [{"label": "Audiovisual", "value": "audiovisual", "selected": false, "description": "A series of visual representations imparting an impression of motion when shown in succession. May or may not include sound. (e.g. films, video, etc.)"}, {"label": "Dataset", "value": "dataset", "selected": false, "description": "Data encoded in a defined structure."}, {"label": "Image", "value": "image", "selected": false, "description": "A visual representation other than text. (e.g. Digitised or born digital images, drawings or photographs)"}, {"label": "Interactive resource", "value": "interactive-resource", "selected": false, "description": "A resource requiring interaction from the user to be understood, executed, or experienced. (e.g. Training modules, files that require use of a viewer (e.g., Flash), or query/response portals)"}, {"label": "Other", "value": "other", "selected": false, "description": "Use this type when your output type does not fall within one of the other categories."}, {"label": "Software", "value": "software", "selected": false, "description": "A computer program other than a computational notebook, in either source code (text) or compiled form. Use this type for general software components supporting scholarly research. Use the â€œComputationalNotebookâ€ value for virtual notebooks."}, {"label": "Sound", "value": "sound", "selected": false, "description": "A resource primarily intended to be heard. (e.g. an audio recording)"}, {"label": "Cuniform Tablet", "value": "cuniform-tablet", "selected": false, "description": "Stone tablets"}, {"label": "8 track tape", "value": "8-track-tape", "selected": false, "description": ""}], "attributes": {"help": "Pick the one that is closest", "label": "Output Type", "multiple": false, "labelTranslationKey": "labels.outputType"}}, "enabled": true, "heading": "Output Type", "required": false}, {"help": "Mark all of the statements that are true about the dataset", "content": {"meta": {"schemaVersion": "1.0"}, "type": "checkBoxes", "options": [{"label": "May contain sensitive data?", "value": "sensitive", "selected": false}, {"label": "May contain personally identifiable information?", "value": "personal", "selected": true}], "attributes": {"labelTranslationKey": "labels.dataFlags"}}, "enabled": true, "heading": "Data Flags", "required": false}, {"help": "Select repository(ies) you would prefer users to deposit in", "content": {"meta": {"schemaVersion": "1.0"}, "type": "repositorySearch", "graphQL": {"query": "query Repositories($term: String, $keywords: [String!], $repositoryType: String, $paginationOptions: PaginationOptions){ repositories(term: $term, keywords: $keywords, repositoryType: $repositoryType, paginationOptions: $paginationOptions) { totalCount currentOffset limit hasNextPage hasPreviousPage availableSortFields items { id name uri description website keywords repositoryTypes } } }", "queryId": "useRepositoriesQuery", "variables": [{"name": "term", "type": "string", "label": "Search for a repository", "minLength": 3, "labelTranslationKey": "RepositorySearch.term"}, {"name": "keywords", "type": "string", "label": "Subject Areas", "minLength": 3, "labelTranslationKey": "RepositorySearch.keywords"}, {"name": "repositoryType", "type": "string", "label": "Repository type", "minLength": 3, "labelTranslationKey": "RepositorySearch.repositoryType"}, {"name": "paginationOptions", "type": "OFFSET", "label": "Pagination Options", "labelTranslationKey": "PaginationOptions.label"}], "answerField": "uri", "displayFields": [{"label": "Name", "propertyName": "name", "labelTranslationKey": "RepositorySearch.name"}, {"label": "Description", "propertyName": "description", "labelTranslationKey": "RepositorySearch.description"}, {"label": "Website", "propertyName": "website", "labelTranslationKey": "RepositorySearch.website"}, {"label": "Subject Areas", "propertyName": "keywords", "labelTranslationKey": "RepositorySearch.keywords"}], "responseField": "repositories.items"}, "attributes": {"help": "", "label": "Repositories", "labelTranslationKey": "labels.repositories"}}, "enabled": true, "heading": "Repositories", "required": false, "preferences": []}, {"help": "Select metadata standard(s) you would prefer users to use", "content": {"meta": {"schemaVersion": "1.0"}, "type": "metadataStandardSearch", "graphQL": {"query": "query MetadataStandards($term: String, $keywords: [String!], $paginationOptions: PaginationOptions){ metadataStandards(term: $term, keywords: $keywords, paginationOptions: $paginationOptions) { totalCount currentOffset limit hasNextPage hasPreviousPage availableSortFields items { id name uri description keywords } } }", "queryId": "useMetadataStandardsQuery", "variables": [{"name": "term", "type": "string", "label": "Search for a metadata standard", "minLength": 3, "labelTranslationKey": "MetadataStandardSearch.term"}, {"name": "keywords", "type": "string", "label": "Subject Areas", "minLength": 3, "labelTranslationKey": "MetadataStandardSearch.keywords"}, {"name": "paginationOptions", "type": "OFFSET", "label": "Pagination Options", "labelTranslationKey": "PaginationOptions.label"}], "answerField": "uri", "displayFields": [{"label": "Name", "propertyName": "name", "labelTranslationKey": "MetadataStandardSearch.name"}, {"label": "Description", "propertyName": "description", "labelTranslationKey": "MetadataStandardSearch.description"}, {"label": "Website", "propertyName": "website", "labelTranslationKey": "MetadataStandardSearch.website"}, {"label": "Subject Areas", "propertyName": "keywords", "labelTranslationKey": "MetadataStandardSearch.keywords"}], "responseField": "metadataStandards.items"}, "attributes": {"help": "", "label": "Metadata Standards", "labelTranslationKey": "labels.metadataStandards"}}, "enabled": true, "heading": "Metadata Standards", "required": false, "preferences": [{"label": "schema.org", "value": "https://rdamsc.bath.ac.uk/api2/m101"}, {"label": "Dublin Core", "value": "https://rdamsc.bath.ac.uk/api2/m15"}]}, {"help": "Select the license you will apply to the research output", "content": {"meta": {"schemaVersion": "1.0"}, "type": "licenseSearch", "graphQL": {"query": "query Licenses{ licenses { id name uri description } }", "queryId": "useLicensesQuery", "variables": [], "answerField": "uri", "displayFields": [{"label": "Name", "propertyName": "name", "labelTranslationKey": "LicenseSearch.name"}, {"label": "Description", "propertyName": "description", "labelTranslationKey": "LicenseSearch.description"}, {"label": "Recommended", "propertyName": "recommended", "labelTranslationKey": "LicenseSearch.recommended"}], "responseField": "licenses"}, "attributes": {"help": "", "label": "Licenses", "labelTranslationKey": "labels.licenses"}}, "enabled": true, "heading": "Licenses", "required": false, "preferences": []}, {"help": "Select the access level for this research output", "content": {"meta": {"schemaVersion": "1.0"}, "type": "radioButtons", "options": [], "attributes": {"help": "This is the access you will allow when the output is first published", "label": "Initial Access Levels", "labelTranslationKey": "labels.initialAccessLevels"}}, "enabled": true, "heading": "Initial Access Levels", "required": false}, {"help": "Enter the title of this research output", "content": {"meta": {"schemaVersion": "1.0"}, "type": "text", "attributes": {"help": "Pick the color that first comes to mind when smelling the output.", "label": "What color will it smell like?", "pattern": "^.+$", "maxLength": 120, "minLength": 0, "defaultValue": "grey"}}, "enabled": true, "heading": "What color will it smell like?", "required": false}], "attributes": {"help": "", "label": "", "canAddRows": true, "initialRows": 1, "canRemoveRows": true, "labelTranslationKey": ""}, "showCommentField": false}','<p>These are the Question requirements: Z, Y, X, W</p>','<p>This is guidance specific to the question (not tagged guidance)</p>',NULL,0,0,2,'2026-05-08 18:25:45',2,'2026-05-08 18:25:45'),
(3687,394,1814,646,2,0,'<p>What is the long-term preservation plan for the dataset?</p>','{"meta": {"schemaVersion": "1.0"}, "type": "textArea", "attributes": {"cols": 20, "rows": 2, "asRichText": true}}',NULL,'<p>&nbsp;</p><p class="guidance_header">Questions to consider:</p><ul><li>Where e.g. in which repository or archive will the data be held?</li><li>What costs if any will your selected data repository or archive charge?</li><li>Have you budgeted for time and effort to prepare the data for sharing / preservation?</li></ul><p>Consider how datasets that have long-term value will be preserved and curated beyond the lifetime of the grant. Also outline the plans for preparing and documenting data for sharing and archiving. If you do not propose to use an established repository, the data management plan should demonstrate that resources and systems will be in place to enable the data to be curated effectively beyond the lifetime of the grant.</p><p>&nbsp;</p>',NULL,0,0,2,'2026-05-08 18:19:26',2,'2026-05-08 18:19:26'),
(3686,394,1814,645,1,0,'<p>Which data are of long-term value and should be retained, shared, and/or preserved?</p>','{"meta": {"schemaVersion": "1.0"}, "type": "textArea", "attributes": {"cols": 20, "rows": 2, "asRichText": true}}',NULL,'<p>&nbsp;</p><p class="guidance_header">Questions to consider:</p><ul><li>What data must be retained/destroyed for contractual, legal, or regulatory purposes?</li><li>How will you decide what other data to keep?</li><li>What are the foreseeable research uses for the data?</li><li>How long will the data be retained and preserved?</li></ul><p>Consider how the data may be reused e.g. to validate your research findings, conduct new studies, or for teaching. Decide which data to keep and for how long. This could be based on any obligations to retain certain data, the potential reuse value, what is economically viable to keep, and any additional effort required to prepare the data for data sharing and preservation. Remember to consider any additional effort required to prepare the data for sharing and preservation, such as changing file formats.</p><p>&nbsp;</p>',NULL,0,0,2,'2026-05-08 18:19:26',2,'2026-05-08 18:19:26');

